{
  "name": "Venture Chess Visualization Trainer",
  "description": "A high-performance, academy-grade chess visualization tool designed for intermediate and advanced students to master mental board tracking.",
  "requestFramePermissions": []
}

export type PieceType = 'QUEEN' | 'ROOK' | 'BISHOP' | 'KNIGHT';

export interface Piece {
  id: string;
  type: PieceType;
  square: number; // 0-63
  isVisible: boolean;
}

export type GamePhase = 'START' | 'OBSERVING' | 'PLAYING' | 'GAMEOVER';

export enum Difficulty {
  EASY = 'EASY',
  INTERMEDIATE = 'INTERMEDIATE',
  HARD = 'HARD'
}

export interface GameState {
  phase: GamePhase;
  difficulty: Difficulty;
  pieces: Piece[];
  targetSquare: number | null;
  score: number;
  strikes: number;
  timeLeft: number;
  lastMoveLine: [number, number] | null; // From square, To square
}

import { PieceType } from '../types';

export function getLegalMoves(square: number, type: PieceType): number[] {
  const row = Math.floor(square / 8);
  const col = square % 8;
  const moves: number[] = [];

  const addIfOnBoard = (r: number, c: number) => {
    if (r >= 0 && r < 8 && c >= 0 && c < 8) {
      moves.push(r * 8 + c);
    }
  };

  switch (type) {
    case 'KNIGHT': {
      const knightOffsets = [
        [-2, -1], [-2, 1], [-1, -2], [-1, 2],
        [1, -2], [1, 2], [2, -1], [2, 1]
      ];
      knightOffsets.forEach(([dr, dc]) => addIfOnBoard(row + dr, col + dc));
      break;
    }
    case 'ROOK': {
      for (let i = 0; i < 8; i++) {
        if (i !== col) addIfOnBoard(row, i);
        if (i !== row) addIfOnBoard(i, col);
      }
      break;
    }
    case 'BISHOP': {
      for (let i = 1; i < 8; i++) {
        addIfOnBoard(row + i, col + i);
        addIfOnBoard(row + i, col - i);
        addIfOnBoard(row - i, col + i);
        addIfOnBoard(row - i, col - i);
      }
      break;
    }
    case 'QUEEN': {
      // Rook moves
      for (let i = 0; i < 8; i++) {
        if (i !== col) addIfOnBoard(row, i);
        if (i !== row) addIfOnBoard(i, col);
      }
      // Bishop moves
      for (let i = 1; i < 8; i++) {
        addIfOnBoard(row + i, col + i);
        addIfOnBoard(row + i, col - i);
        addIfOnBoard(row - i, col + i);
        addIfOnBoard(row - i, col - i);
      }
      break;
    }
  }

  return [...new Set(moves)];
}

export function canPieceReach(from: number, to: number, type: PieceType): boolean {
  return getLegalMoves(from, type).includes(to);
}

export function getRandomSquare(exclude: number[] = []): number {
  let sq;
  do {
    sq = Math.floor(Math.random() * 64);
  } while (exclude.includes(sq));
  return sq;
}

import React from 'react';
import { Piece, PieceType } from '../types';
import { COLORS, PIECE_ICONS } from '../constants';

interface ChessBoardProps {
  pieces: Piece[];
  targetSquare: number | null;
  lastMoveLine: [number, number] | null;
}

const ChessBoard: React.FC<ChessBoardProps> = ({ pieces, targetSquare, lastMoveLine }) => {
  const getSquareColor = (idx: number) => {
    const row = Math.floor(idx / 8);
    const col = idx % 8;
    return (row + col) % 2 === 0 ? COLORS.BOARD_LIGHT : COLORS.BOARD_DARK;
  };

  const getCoordinates = (idx: number) => {
    const row = Math.floor(idx / 8);
    const col = idx % 8;
    return {
      x: col * 12.5 + 6.25,
      y: row * 12.5 + 6.25,
    };
  };

  return (
    <div className="relative aspect-square w-full max-w-[500px] border-4 border-slate-700 shadow-2xl rounded-sm overflow-hidden select-none">
      {/* Grid */}
      <div className="grid grid-cols-8 grid-rows-8 w-full h-full">
        {Array.from({ length: 64 }).map((_, i) => (
          <div
            key={i}
            style={{ backgroundColor: getSquareColor(i) }}
            className="relative flex items-center justify-center"
          >
            {/* Target Pulse/Outline */}
            {targetSquare === i && (
              <div className="absolute inset-0 border-4 border-amber-500/60 animate-pulse pointer-events-none" />
            )}

            {/* Invisible Position Marker (for debug or very subtle hint if allowed, but here we stick to rules) */}
          </div>
        ))}
      </div>

      {/* Pieces (Only visible if isVisible is true) */}
      <div className="absolute inset-0 grid grid-cols-8 grid-rows-8 pointer-events-none">
        {Array.from({ length: 64 }).map((_, i) => {
          const piece = pieces.find((p) => p.square === i);
          return (
            <div key={i} className="flex items-center justify-center p-1 transition-opacity duration-700">
              {piece && piece.isVisible && (
                <div className="w-4/5 h-4/5">
                  {PIECE_ICONS[piece.type]}
                </div>
              )}
            </div>
          );
        })}
      </div>

      {/* Elegant Move Line */}
      {lastMoveLine && (
        <svg className="absolute inset-0 w-full h-full pointer-events-none" viewBox="0 0 100 100">
          <line
            x1={getCoordinates(lastMoveLine[0]).x}
            y1={getCoordinates(lastMoveLine[0]).y}
            x2={getCoordinates(lastMoveLine[1]).x}
            y2={getCoordinates(lastMoveLine[1]).y}
            stroke={COLORS.GOLD_ACCENT}
            strokeWidth="0.8"
            strokeDasharray="1,1"
            className="animate-[draw_0.5s_ease-out]"
          />
        </svg>
      )}
    </div>
  );
};

export default ChessBoard;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { GameState, GamePhase, Difficulty, Piece, PieceType } from './types';
import { getRandomSquare, getLegalMoves, canPieceReach } from './services/chessLogic';
import { PIECE_ICONS, COLORS } from './constants';
import ChessBoard from './components/ChessBoard';

const OBSERVATION_TIME = 5;
const START_TIME = 120; // 2 minutes for a full session
const MAX_STRIKES = 5;

const App: React.FC = () => {
  const [state, setState] = useState<GameState>({
    phase: 'START',
    difficulty: Difficulty.EASY,
    pieces: [],
    targetSquare: null,
    score: 0,
    strikes: 0,
    timeLeft: START_TIME,
    lastMoveLine: null,
  });

  const timerRef = useRef<NodeJS.Timeout | null>(null);
  const [disabledOptions, setDisabledOptions] = useState<PieceType[]>([]);

  // Sound effects are prohibited by prompt, so we focus on visuals

  const generateNewTarget = useCallback((currentPieces: Piece[]) => {
    // Pick a piece to move
    const randomPiece = currentPieces[Math.floor(Math.random() * currentPieces.length)];
    const legalMoves = getLegalMoves(randomPiece.square, randomPiece.type);

    // Controlled randomness: try to find a square that doesn't have another piece
    const availableTargets = legalMoves.filter(m => !currentPieces.some(p => p.square === m));

    if (availableTargets.length === 0) {
      // Fallback: pick any random move if blocked
      return legalMoves[Math.floor(Math.random() * legalMoves.length)];
    }

    return availableTargets[Math.floor(Math.random() * availableTargets.length)];
  }, []);

  const startGame = (diff: Difficulty) => {
    let pieceCount = 2;
    if (diff === Difficulty.INTERMEDIATE) pieceCount = 3;
    if (diff === Difficulty.HARD) pieceCount = 4;

    const pieceTypes: PieceType[] = ['QUEEN', 'ROOK', 'BISHOP', 'KNIGHT'];
    const selectedPieces: Piece[] = [];
    const usedSquares: number[] = [];

    for (let i = 0; i < pieceCount; i++) {
      const type = pieceTypes[Math.floor(Math.random() * pieceTypes.length)];
      const square = getRandomSquare(usedSquares);
      usedSquares.push(square);
      selectedPieces.push({
        id: `p-${i}`,
        type,
        square,
        isVisible: true
      });
    }

    setState({
      phase: 'OBSERVING',
      difficulty: diff,
      pieces: selectedPieces,
      targetSquare: null,
      score: 0,
      strikes: 0,
      timeLeft: START_TIME,
      lastMoveLine: null,
    });

    // Observation Timer
    setTimeout(() => {
      setState(prev => {
        const nextTarget = generateNewTarget(prev.pieces);
        return {
          ...prev,
          phase: 'PLAYING',
          pieces: prev.pieces.map(p => ({ ...p, isVisible: false })),
          targetSquare: nextTarget,
        };
      });
    }, OBSERVATION_TIME * 1000);
  };

  useEffect(() => {
    if (state.phase === 'PLAYING') {
      timerRef.current = setInterval(() => {
        setState(prev => {
          if (prev.timeLeft <= 1) {
            clearInterval(timerRef.current!);
            return { ...prev, timeLeft: 0, phase: 'GAMEOVER' };
          }
          return { ...prev, timeLeft: prev.timeLeft - 1 };
        });
      }, 1000);
    }
    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, [state.phase]);

  const handlePieceSelect = (type: PieceType) => {
    if (state.phase !== 'PLAYING' || state.targetSquare === null) return;

    // Which piece can reach targetSquare?
    const validPiece = state.pieces.find(p => canPieceReach(p.square, state.targetSquare!, p.type));

    if (validPiece && validPiece.type === type) {
      // Correct!
      const oldSquare = validPiece.square;
      const newSquare = state.targetSquare!;

      const updatedPieces = state.pieces.map(p => 
        p.id === validPiece.id ? { ...p, square: newSquare } : p
      );

      setDisabledOptions([]);
      const nextTarget = generateNewTarget(updatedPieces);

      setState(prev => ({
        ...prev,
        score: prev.score + 10,
        pieces: updatedPieces,
        lastMoveLine: [oldSquare, newSquare],
        targetSquare: nextTarget,
      }));
    } else {
      // Wrong!
      setDisabledOptions(prev => [...prev, type]);
      setState(prev => {
        const newStrikes = prev.strikes + 1;
        if (newStrikes >= MAX_STRIKES) {
          clearInterval(timerRef.current!);
          return { ...prev, strikes: newStrikes, phase: 'GAMEOVER' };
        }
        return { ...prev, strikes: newStrikes };
      });
    }
  };

  const renderStartScreen = () => (
    <div className="flex flex-col items-center justify-center h-full space-y-8 animate-in fade-in zoom-in duration-700">
      <div className="text-center">
        <h1 className="text-4xl font-bold tracking-[0.2em] mb-2 uppercase text-slate-200">Visualization</h1>
        <p className="text-slate-500 font-light tracking-widest text-sm italic">Venture Chess Academy</p>
      </div>

      <div className="flex flex-col space-y-4 w-64">
        <button 
          onClick={() => startGame(Difficulty.EASY)}
          className="border border-slate-700 py-3 px-6 hover:bg-slate-800 transition-colors uppercase tracking-widest text-xs font-semibold"
        >
          Level I: Novice
        </button>
        <button 
          onClick={() => startGame(Difficulty.INTERMEDIATE)}
          className="border border-slate-700 py-3 px-6 hover:bg-slate-800 transition-colors uppercase tracking-widest text-xs font-semibold"
        >
          Level II: Intermediate
        </button>
        <button 
          onClick={() => startGame(Difficulty.HARD)}
          className="border border-slate-700 py-3 px-6 hover:bg-slate-800 transition-colors uppercase tracking-widest text-xs font-semibold"
        >
          Level III: Master
        </button>
      </div>
    </div>
  );

  const renderGameScreen = () => (
    <div className="flex flex-col items-center w-full max-w-4xl px-4 animate-in fade-in duration-500">
      {/* HUD Header */}
      <div className="flex justify-between w-full mb-8 font-mono text-sm tracking-tighter text-slate-400">
        <div className="flex space-x-8">
          <div>
            SCORE: <span className="text-slate-100">{state.score.toString().padStart(4, '0')}</span>
          </div>
          <div>
            TIME: <span className={state.timeLeft < 10 ? 'text-amber-600 animate-pulse' : 'text-slate-100'}>
              {Math.floor(state.timeLeft / 60)}:{(state.timeLeft % 60).toString().padStart(2, '0')}
            </span>
          </div>
        </div>
        <div className="flex space-x-1">
          {Array.from({ length: MAX_STRIKES }).map((_, i) => (
            <div 
              key={i} 
              className={`w-3 h-3 border ${i < state.strikes ? 'bg-amber-800 border-amber-900' : 'border-slate-700'}`} 
            />
          ))}
        </div>
      </div>

      {/* Main Board */}
      <div className="relative group">
        <ChessBoard 
          pieces={state.pieces} 
          targetSquare={state.targetSquare} 
          lastMoveLine={state.lastMoveLine} 
        />
        {state.phase === 'OBSERVING' && (
          <div className="absolute inset-0 flex items-center justify-center bg-black/40 backdrop-blur-[2px]">
            <div className="text-white text-6xl font-black tracking-widest opacity-50">
              MEMORIZE
            </div>
          </div>
        )}
      </div>

      {/* Piece Selection Options */}
      <div className={`mt-12 flex justify-center space-x-6 transition-opacity duration-300 ${state.phase !== 'PLAYING' ? 'opacity-20 pointer-events-none' : 'opacity-100'}`}>
        {(['QUEEN', 'ROOK', 'BISHOP', 'KNIGHT'] as PieceType[]).map((type) => {
          // Only show icons for pieces active in the game to avoid clutter
          const isActive = state.pieces.some(p => p.type === type);
          if (!isActive) return null;

          const isDisabled = disabledOptions.includes(type);

          return (
            <button
              key={type}
              onClick={() => handlePieceSelect(type)}
              disabled={isDisabled}
              className={`w-20 h-20 p-4 border border-slate-800 rounded-sm transition-all bg-slate-900/40 hover:bg-slate-800 hover:border-slate-600 active:scale-95 ${isDisabled ? 'opacity-20 grayscale' : 'opacity-100'}`}
            >
              <div className="w-full h-full filter invert brightness-200">
                {PIECE_ICONS[type]}
              </div>
            </button>
          );
        })}
      </div>

      {state.phase === 'PLAYING' && (
        <p className="mt-8 text-slate-600 text-[10px] uppercase tracking-[0.3em] font-medium">
          Identify the piece capable of reaching the highlighted square
        </p>
      )}
    </div>
  );

  const renderGameOver = () => (
    <div className="flex flex-col items-center justify-center h-full space-y-12 animate-in fade-in slide-in-from-bottom-10 duration-1000">
      <div className="text-center">
        <h2 className="text-5xl font-extralight tracking-[0.4em] mb-4 text-slate-100 uppercase">Assessment Complete</h2>
        <div className="h-px w-24 bg-slate-800 mx-auto" />
      </div>

      <div className="text-center space-y-1">
        <div className="text-slate-500 uppercase tracking-widest text-[10px]">Final Visualization Score</div>
        <div className="text-7xl font-bold text-amber-600 tracking-tighter">{state.score}</div>
      </div>

      <div className="flex space-x-4">
        <button 
          onClick={() => startGame(state.difficulty)}
          className="bg-slate-100 text-slate-900 py-3 px-8 text-xs font-bold uppercase tracking-widest hover:bg-white transition-colors"
        >
          Replay Exercise
        </button>
        <button 
          onClick={() => setState(prev => ({ ...prev, phase: 'START' }))}
          className="border border-slate-700 text-slate-300 py-3 px-8 text-xs font-bold uppercase tracking-widest hover:bg-slate-800 transition-colors"
        >
          Home
        </button>
      </div>
    </div>
  );

  return (
    <div className="relative min-h-screen w-full bg-[#0F172A] flex items-center justify-center overflow-hidden">
      <div className="parchment-grain absolute inset-0 z-0" />

      {/* Subtle vignette */}
      <div className="absolute inset-0 pointer-events-none shadow-[inset_0_0_150px_rgba(0,0,0,0.8)] z-10" />

      <main className="relative z-20 w-full h-full flex flex-col items-center">
        {state.phase === 'START' && renderStartScreen()}
        {(state.phase === 'OBSERVING' || state.phase === 'PLAYING') && renderGameScreen()}
        {state.phase === 'GAMEOVER' && renderGameOver()}
      </main>

      {/* Decorative Branding Elements */}
      <div className="absolute top-8 left-8 text-[10px] text-slate-700 tracking-[0.5em] font-bold uppercase hidden md:block">
        Visualisation Trainer v1.4
      </div>
      <div className="absolute bottom-8 right-8 text-[10px] text-slate-700 tracking-[0.5em] font-bold uppercase hidden md:block">
        Property of Venture Chess Academy
      </div>
    </div>
  );
};

export default App;

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

