import React from 'react';
import { Piece } from '../types';
import { PALETTE, PIECE_ICONS } from '../constants';

interface ChessBoardProps {
  pieces: Piece[];
  targetSquare: number | null;
  lastMoveLine: [number, number] | null;
}

const ChessBoard: React.FC<ChessBoardProps> = ({ pieces, targetSquare, lastMoveLine }) => {
  const ranks = ['8', '7', '6', '5', '4', '3', '2', '1'];
  const files = ['a', 'b', 'c', 'd', 'e', 'f', 'g', 'h'];

  const getSquareColor = (idx: number) => {
    const row = Math.floor(idx / 8);
    const col = idx % 8;
    return (row + col) % 2 === 0 ? PALETTE.BOARD_LIGHT : PALETTE.BOARD_DARK;
  };

  const getCoordinatesForLine = (idx: number) => {
    const row = Math.floor(idx / 8);
    const col = idx % 8;
    return {
      x: col * 12.5 + 6.25,
      y: row * 12.5 + 6.25,
    };
  };

  return (
    <div 
      className="relative p-6 rounded-sm border"
      style={{ 
        backgroundColor: PALETTE.SECONDARY_BG, 
        borderColor: PALETTE.MUTED_ELEMENTS 
      }}
    >
      {/* File Labels (Top) */}
      <div className="flex w-full mb-1 pl-4 pr-4">
        {files.map(f => (
          <div 
            key={f} 
            className="flex-1 text-center text-[10px] font-bold uppercase tracking-widest"
            style={{ color: PALETTE.MUTED_ELEMENTS }}
          >{f}</div>
        ))}
      </div>

      <div className="flex">
        {/* Rank Labels (Left) */}
        <div className="flex flex-col mr-1 h-[300px] sm:h-[400px] md:h-[500px]">
          {ranks.map(r => (
            <div 
              key={r} 
              className="flex-1 flex items-center justify-center text-[10px] font-bold"
              style={{ color: PALETTE.MUTED_ELEMENTS }}
            >{r}</div>
          ))}
        </div>

        {/* Literal 8x8 Chessboard */}
        <div 
          className="relative aspect-square w-[300px] sm:w-[400px] md:w-[500px] border-4 rounded-sm overflow-hidden select-none"
          style={{ borderColor: PALETTE.MUTED_ELEMENTS }}
        >
          {/* Grid of 64 distinct squares */}
          <div className="grid grid-cols-8 grid-rows-8 w-full h-full">
            {Array.from({ length: 64 }).map((_, i) => (
              <div
                key={i}
                style={{ backgroundColor: getSquareColor(i) }}
                className="relative flex items-center justify-center"
              >
                {/* Highlighted Target Square */}
                {targetSquare === i && (
                  <div 
                    className="absolute inset-0 border-[3px] pointer-events-none z-10" 
                    style={{ borderColor: PALETTE.HIGHLIGHT_OUTLINE }}
                  />
                )}
              </div>
            ))}
          </div>

          {/* Pieces Layer */}
          <div className="absolute inset-0 grid grid-cols-8 grid-rows-8 pointer-events-none">
            {Array.from({ length: 64 }).map((_, i) => {
              const piece = pieces.find((p) => p.square === i);
              return (
                <div key={i} className="flex items-center justify-center p-1">
                  {piece && piece.isVisible && (
                    <div className="w-[85%] h-[85%]">
                      {PIECE_ICONS[piece.type]}
                    </div>
                  )}
                </div>
              );
            })}
          </div>

          {/* Move Line Layer */}
          {lastMoveLine && (
            <svg className="absolute inset-0 w-full h-full pointer-events-none z-20" viewBox="0 0 100 100">
              <line
                x1={getCoordinatesForLine(lastMoveLine[0]).x}
                y1={getCoordinatesForLine(lastMoveLine[0]).y}
                x2={getCoordinatesForLine(lastMoveLine[1]).x}
                y2={getCoordinatesForLine(lastMoveLine[1]).y}
                stroke={PALETTE.PATH_INDICATOR}
                strokeWidth="0.4"
                className="opacity-60"
                style={{ strokeDasharray: '0.5, 0.5' }}
              />
            </svg>
          )}
        </div>

        {/* Rank Labels (Right) */}
        <div className="flex flex-col ml-1 h-[300px] sm:h-[400px] md:h-[500px]">
          {ranks.map(r => (
            <div 
              key={r} 
              className="flex-1 flex items-center justify-center text-[10px] font-bold"
              style={{ color: PALETTE.MUTED_ELEMENTS }}
            >{r}</div>
          ))}
        </div>
      </div>

      {/* File Labels (Bottom) */}
      <div className="flex w-full mt-1 pl-4 pr-4">
        {files.map(f => (
          <div 
            key={f} 
            className="flex-1 text-center text-[10px] font-bold uppercase tracking-widest"
            style={{ color: PALETTE.MUTED_ELEMENTS }}
          >{f}</div>
        ))}
      </div>
    </div>
  );
};

