import React, { useState, useEffect, useCallback, useRef } from 'react';
import { GameState, GamePhase, Difficulty, Piece, PieceType } from './types';
import { getRandomSquare, getLegalMoves, canPieceReach } from './services/chessLogic';
import { PALETTE, PIECE_ICONS } from './constants';
import ChessBoard from './components/ChessBoard';

const OBSERVATION_TIME = 5;
const START_TIME = 180; 
const MAX_STRIKES = 5;

const App: React.FC = () => {
  const [state, setState] = useState<GameState>({
    phase: 'START',
    difficulty: Difficulty.EASY,
    pieces: [],
    targetSquare: null,
    score: 0,
    strikes: 0,
    timeLeft: START_TIME,
    lastMoveLine: null,
    correctMoves: 0,
    currentStreak: 0,
    bestStreak: 0,
  });

  const timerRef = useRef<any>(null);
  const [disabledOptions, setDisabledOptions] = useState<PieceType[]>([]);
  const [pulsingPiece, setPulsingPiece] = useState<PieceType | null>(null);

  const generateNewTarget = useCallback((currentPieces: Piece[]) => {
    const randomPiece = currentPieces[Math.floor(Math.random() * currentPieces.length)];
    const legalMoves = getLegalMoves(randomPiece.square, randomPiece.type);
    const availableTargets = legalMoves.filter(m => !currentPieces.some(p => p.square === m));

    if (availableTargets.length === 0) {
      return legalMoves[Math.floor(Math.random() * legalMoves.length)];
    }

    return availableTargets[Math.floor(Math.random() * availableTargets.length)];
  }, []);

  const startGame = (diff: Difficulty) => {
    let pieceCount = 2;
    if (diff === Difficulty.INTERMEDIATE) pieceCount = 3;
    if (diff === Difficulty.HARD) pieceCount = 4;

    const pieceTypes: PieceType[] = ['QUEEN', 'ROOK', 'BISHOP', 'KNIGHT'];
    const selectedPieces: Piece[] = [];
    const usedSquares: number[] = [];

    for (let i = 0; i < pieceCount; i++) {
      let type;
      if (diff === Difficulty.EASY && i === 1) {
        const firstType = selectedPieces[0].type;
        const available = pieceTypes.filter(t => t !== firstType);
        type = available[Math.floor(Math.random() * available.length)];
      } else {
        type = pieceTypes[Math.floor(Math.random() * pieceTypes.length)];
      }

      const square = getRandomSquare(usedSquares);
      usedSquares.push(square);
      selectedPieces.push({
        id: `p-${i}`,
        type,
        square,
        isVisible: true
      });
    }

    setState({
      phase: 'OBSERVING',
      difficulty: diff,
      pieces: selectedPieces,
      targetSquare: null,
      score: 0,
      strikes: 0,
      timeLeft: START_TIME,
      lastMoveLine: null,
      correctMoves: 0,
      currentStreak: 0,
      bestStreak: 0,
    });

    setTimeout(() => {
      setState(prev => {
        const nextTarget = generateNewTarget(prev.pieces);
        return {
          ...prev,
          phase: 'PLAYING',
          pieces: prev.pieces.map(p => ({ ...p, isVisible: false })),
          targetSquare: nextTarget,
        };
      });
    }, OBSERVATION_TIME * 1000);
  };

  useEffect(() => {
    if (state.phase === 'PLAYING') {
      timerRef.current = setInterval(() => {
        setState(prev => {
          if (prev.timeLeft <= 1) {
            clearInterval(timerRef.current!);
            return { ...prev, timeLeft: 0, phase: 'GAMEOVER' };
          }
          return { ...prev, timeLeft: prev.timeLeft - 1 };
        });
      }, 1000);
    }
    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, [state.phase]);

  const handlePieceSelect = (type: PieceType) => {
    if (state.phase !== 'PLAYING' || state.targetSquare === null) return;

    const validPiece = state.pieces.find(p => p.type === type && canPieceReach(p.square, state.targetSquare!, p.type));

    if (validPiece) {
      const oldSquare = validPiece.square;
      const newSquare = state.targetSquare!;

      const updatedPieces = state.pieces.map(p => 
        p.id === validPiece.id ? { ...p, square: newSquare } : p
      );

      setDisabledOptions([]);
      const nextTarget = generateNewTarget(updatedPieces);

      setState(prev => {
        const newStreak = prev.currentStreak + 1;
        return {
          ...prev,
          score: prev.score + 10,
          pieces: updatedPieces,
          lastMoveLine: [oldSquare, newSquare],
          targetSquare: nextTarget,
          correctMoves: prev.correctMoves + 1,
          currentStreak: newStreak,
          bestStreak: Math.max(prev.bestStreak, newStreak),
        };
      });
    } else {
      setPulsingPiece(type);
      setTimeout(() => setPulsingPiece(null), 400);

      setDisabledOptions(prev => [...prev, type]);
      setState(prev => {
        const newStrikes = prev.strikes + 1;
        if (newStrikes >= MAX_STRIKES) {
          clearInterval(timerRef.current!);
          return { ...prev, strikes: newStrikes, phase: 'GAMEOVER', currentStreak: 0 };
        }
        return { ...prev, strikes: newStrikes, currentStreak: 0 };
      });
    }
  };

  const renderStartScreen = () => (
    <div className="flex flex-col items-center justify-center h-full space-y-12 animate-in fade-in duration-1000">
      <div className="text-center">
        <h1 
          className="text-5xl font-extralight tracking-[0.3em] mb-4 uppercase"
          style={{ color: PALETTE.PRIMARY_TEXT }}
        >Academy Drill</h1>
        <p 
          className="font-bold tracking-[0.5em] text-[10px] uppercase"
          style={{ color: PALETTE.HIGHLIGHT_OUTLINE }}
        >Venture Chess Visualization Trainer</p>
      </div>

      <div className="grid grid-cols-1 gap-4 w-72">
        {[
          { id: Difficulty.EASY, label: 'Level I: Two Pieces' },
          { id: Difficulty.INTERMEDIATE, label: 'Level II: Three Pieces' },
          { id: Difficulty.HARD, label: 'Level III: Four Pieces' }
        ].map(diff => (
          <button 
            key={diff.id}
            onClick={() => startGame(diff.id)}
            className="border py-4 px-6 transition-all uppercase tracking-[0.2em] text-[10px] font-bold shadow-sm"
            style={{ 
              backgroundColor: PALETTE.SECONDARY_BG,
              borderColor: PALETTE.MUTED_ELEMENTS,
              color: PALETTE.MUTED_ELEMENTS
            }}
            onMouseOver={(e) => {
              e.currentTarget.style.backgroundColor = PALETTE.PRIMARY_TEXT;
              e.currentTarget.style.color = PALETTE.PRIMARY_BG;
            }}
            onMouseOut={(e) => {
              e.currentTarget.style.backgroundColor = PALETTE.SECONDARY_BG;
              e.currentTarget.style.color = PALETTE.MUTED_ELEMENTS;
            }}
          >
            {diff.label}
          </button>
        ))}
      </div>
    </div>
  );

  const renderGameScreen = () => (
    <div className="flex flex-col items-center w-full max-w-6xl px-4 animate-in fade-in duration-500">
      <div 
        className="flex justify-between items-center w-full max-w-[600px] mb-6 font-mono text-xs tracking-widest border-b pb-4"
        style={{ borderColor: `${PALETTE.MUTED_ELEMENTS}40` }}
      >
        <div className="flex space-x-12">
          <div className="flex flex-col">
            <span className="text-[8px] mb-1" style={{ color: PALETTE.MUTED_ELEMENTS }}>CUMULATIVE SCORE</span>
            <span className="text-lg font-bold" style={{ color: PALETTE.PRIMARY_TEXT }}>{state.score.toString().padStart(4, '0')}</span>
          </div>
          <div className="flex flex-col">
            <span className="text-[8px] mb-1" style={{ color: PALETTE.MUTED_ELEMENTS }}>SESSION TIME</span>
            <span className="text-lg font-bold" style={{ color: state.timeLeft < 15 ? PALETTE.HIGHLIGHT_OUTLINE : PALETTE.PRIMARY_TEXT }}>
              {Math.floor(state.timeLeft / 60)}:{(state.timeLeft % 60).toString().padStart(2, '0')}
            </span>
          </div>
        </div>

        <div className="flex flex-col items-end">
          <span className="text-[8px] mb-2" style={{ color: PALETTE.MUTED_ELEMENTS }}>INTEGRITY STRIKES</span>
          <div className="flex space-x-1.5">
            {Array.from({ length: MAX_STRIKES }).map((_, i) => (
              <div 
                key={i} 
                className="w-4 h-1 transition-colors duration-300"
                style={{ backgroundColor: i < state.strikes ? PALETTE.HIGHLIGHT_OUTLINE : `${PALETTE.MUTED_ELEMENTS}40` }} 
              />
            ))}
          </div>
        </div>
      </div>

      <div className="shadow-2xl">
        <ChessBoard 
          pieces={state.pieces} 
          targetSquare={state.targetSquare} 
          lastMoveLine={state.lastMoveLine} 
        />
      </div>

      <div className="mt-12 flex flex-col items-center w-full max-w-[500px]">
        {/* Piece Selection Area - Exact visual match for user screenshot */}
        <div 
          className="flex justify-center space-x-6 p-8 border shadow-lg rounded-sm"
          style={{ 
            borderColor: `${PALETTE.MUTED_ELEMENTS}20`,
            backgroundColor: PALETTE.SECONDARY_BG,
            opacity: state.phase !== 'PLAYING' ? 0.2 : 1 
          }}
        >
          {(['QUEEN', 'ROOK', 'BISHOP', 'KNIGHT'] as PieceType[]).map((type) => {
            const isUsedInSession = state.pieces.some(p => p.type === type);
            const isDisabled = disabledOptions.includes(type);
            const isPulsing = pulsingPiece === type;

            return (
              <button
                key={type}
                onClick={() => handlePieceSelect(type)}
                disabled={isDisabled || !isUsedInSession}
                className={`w-24 h-24 p-2 border transition-all active:scale-95 flex flex-col items-center justify-between ${isPulsing ? 'animate-subtle-pulse' : ''}`}
                style={{ 
                  display: isUsedInSession ? 'flex' : 'none',
                  backgroundColor: PALETTE.SECONDARY_BG,
                  borderColor: isPulsing ? PALETTE.HIGHLIGHT_OUTLINE : `${PALETTE.MUTED_ELEMENTS}40`,
                  opacity: isDisabled && !isPulsing ? 0.2 : 1,
                  filter: isDisabled && !isPulsing ? 'grayscale(1)' : 'none'
                }}
              >
                <div className="w-full h-16 flex items-center justify-center p-1">
                  {PIECE_ICONS[type]}
                </div>
                <span className="text-[10px] font-bold uppercase tracking-widest pb-1" style={{ color: PALETTE.MUTED_ELEMENTS }}>{type}</span>
              </button>
            );
          })}
        </div>

        <div 
          className="mt-10 text-[11px] font-bold uppercase tracking-[0.5em] text-center"
          style={{ color: state.phase === 'OBSERVING' ? PALETTE.HIGHLIGHT_OUTLINE : PALETTE.MUTED_ELEMENTS }}
        >
          {state.phase === 'OBSERVING' ? 'Observation Phase: Memorize All Pieces' : 'Which piece can move to the highlighted square?'}
        </div>
      </div>
    </div>
  );

  const renderGameOver = () => (
    <div className="flex flex-col items-center justify-center h-full space-y-12 animate-in fade-in zoom-in duration-1000">
      <div className="text-center">
        <h2 className="text-5xl font-extralight tracking-[0.3em] mb-4 uppercase" style={{ color: PALETTE.PRIMARY_TEXT }}>Session Over</h2>
        <p className="uppercase tracking-[0.4em] text-[10px] font-bold" style={{ color: PALETTE.MUTED_ELEMENTS }}>Analysis Terminated</p>
      </div>

      <div className="flex flex-col items-center space-y-2">
        <div className="uppercase tracking-[0.5em] text-[8px] font-bold" style={{ color: PALETTE.MUTED_ELEMENTS }}>Performance Rating</div>
        <div className="text-8xl font-black tracking-tighter" style={{ color: PALETTE.HIGHLIGHT_OUTLINE }}>{state.score}</div>
      </div>

      <div className="flex flex-col items-center space-y-4 w-full max-w-sm">
        <div className="flex justify-between w-full border-b pb-2" style={{ borderColor: `${PALETTE.MUTED_ELEMENTS}40` }}>
          <span className="uppercase tracking-[0.3em] text-[9px] font-bold" style={{ color: PALETTE.MUTED_ELEMENTS }}>Correct Sequence</span>
          <span className="text-xs font-mono font-bold" style={{ color: PALETTE.PRIMARY_TEXT }}>{state.correctMoves}</span>
        </div>
        <div className="flex justify-between w-full border-b pb-2" style={{ borderColor: `${PALETTE.MUTED_ELEMENTS}40` }}>
          <span className="uppercase tracking-[0.3em] text-[9px] font-bold" style={{ color: PALETTE.MUTED_ELEMENTS }}>Peak Accuracy Streak</span>
          <span className="text-xs font-mono font-bold" style={{ color: PALETTE.PRIMARY_TEXT }}>{state.bestStreak}</span>
        </div>
      </div>

      <div className="flex space-x-6 pt-4">
        <button 
          onClick={() => startGame(state.difficulty)}
          className="border py-4 px-10 text-[10px] font-bold uppercase tracking-[0.3em] transition-all shadow-sm"
          style={{ borderColor: PALETTE.MUTED_ELEMENTS, color: PALETTE.PRIMARY_TEXT }}
        >
          Retry Drill
        </button>
        <button 
          onClick={() => setState(prev => ({ ...prev, phase: 'START' }))}
          className="py-4 px-10 text-[10px] font-bold uppercase tracking-[0.3em] transition-all shadow-md"
          style={{ backgroundColor: PALETTE.PRIMARY_TEXT, color: PALETTE.PRIMARY_BG }}
        >
          Exit to Hub
        </button>
      </div>
    </div>
  );

  return (
    <div className="relative min-h-screen w-full flex items-center justify-center overflow-hidden" style={{ backgroundColor: PALETTE.PRIMARY_BG }}>
      <div className="absolute inset-0 pointer-events-none z-10" style={{ boxShadow: 'inset 0 0 100px rgba(0,0,0,0.05)' }} />

      <main className="relative z-20 w-full h-full flex flex-col items-center py-12">
        {state.phase === 'START' && renderStartScreen()}
        {(state.phase === 'OBSERVING' || state.phase === 'PLAYING') && renderGameScreen()}
        {state.phase === 'GAMEOVER' && renderGameOver()}
      </main>

      <div className="absolute top-12 left-12 flex flex-col opacity-40 pointer-events-none hidden lg:flex">
        <div className="text-[10px] font-bold uppercase tracking-[1em]" style={{ color: PALETTE.MUTED_ELEMENTS }}>Venture</div>
        <div className="text-[10px] font-bold uppercase tracking-[1em]" style={{ color: PALETTE.MUTED_ELEMENTS }}>Academy</div>
      </div>
    </div>
  );
};

export default App;

import React from 'react';
import { Piece } from '../types';
import { PALETTE, PIECE_ICONS } from '../constants';

interface ChessBoardProps {
  pieces: Piece[];
  targetSquare: number | null;
  lastMoveLine: [number, number] | null;
}

const ChessBoard: React.FC<ChessBoardProps> = ({ pieces, targetSquare, lastMoveLine }) => {
  const ranks = ['8', '7', '6', '5', '4', '3', '2', '1'];
  const files = ['a', 'b', 'c', 'd', 'e', 'f', 'g', 'h'];

  const getSquareColor = (idx: number) => {
    const row = Math.floor(idx / 8);
    const col = idx % 8;
    return (row + col) % 2 === 0 ? PALETTE.BOARD_LIGHT : PALETTE.BOARD_DARK;
  };

  const getCoordinatesForLine = (idx: number) => {
    const row = Math.floor(idx / 8);
    const col = idx % 8;
    return {
      x: col * 12.5 + 6.25,
      y: row * 12.5 + 6.25,
    };
  };

  return (
    <div 
      className="relative p-2 rounded-sm"
      style={{ 
        backgroundColor: '#D1D5DB', // Subtle outer border area
        boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1), 0 2px 4px -2px rgb(0 0 0 / 0.1)'
      }}
    >
      <div 
        className="relative aspect-square w-[320px] sm:w-[440px] md:w-[540px] border border-gray-400 overflow-hidden select-none"
      >
        {/* Literal 8x8 Chessboard */}
        <div className="grid grid-cols-8 grid-rows-8 w-full h-full">
          {Array.from({ length: 64 }).map((_, i) => {
            const row = Math.floor(i / 8);
            const col = i % 8;
            const isFirstCol = col === 0;
            const isLastRow = row === 7;

            return (
              <div
                key={i}
                style={{ backgroundColor: getSquareColor(i) }}
                className="relative flex items-center justify-center"
              >
                {/* Lichess style internal coordinates */}
                {isFirstCol && (
                  <span 
                    className="absolute left-0.5 top-0.5 text-[8px] font-bold pointer-events-none"
                    style={{ color: (row + col) % 2 === 0 ? PALETTE.BOARD_DARK : PALETTE.BOARD_LIGHT }}
                  >
                    {ranks[row]}
                  </span>
                )}
                {isLastRow && (
                  <span 
                    className="absolute right-0.5 bottom-0.5 text-[8px] font-bold pointer-events-none"
                    style={{ color: (row + col) % 2 === 0 ? PALETTE.BOARD_DARK : PALETTE.BOARD_LIGHT }}
                  >
                    {files[col]}
                  </span>
                )}

                {/* Highlighted Target Square */}
                {targetSquare === i && (
                  <div 
                    className="absolute inset-0 bg-blue-500/30 border-[3px] pointer-events-none z-10" 
                    style={{ borderColor: PALETTE.HIGHLIGHT_OUTLINE }}
                  />
                )}
              </div>
            );
          })}
        </div>

        {/* Pieces Layer */}
        <div className="absolute inset-0 grid grid-cols-8 grid-rows-8 pointer-events-none">
          {Array.from({ length: 64 }).map((_, i) => {
            const piece = pieces.find((p) => p.square === i);
            return (
              <div key={i} className="flex items-center justify-center p-0.5">
                {piece && piece.isVisible && (
                  <div className="w-[95%] h-[95%] flex items-center justify-center">
                    {PIECE_ICONS[piece.type]}
                  </div>
                )}
              </div>
            );
          })}
        </div>

        {/* Move Line Layer */}
        {lastMoveLine && (
          <svg className="absolute inset-0 w-full h-full pointer-events-none z-20" viewBox="0 0 100 100">
            <line
              x1={getCoordinatesForLine(lastMoveLine[0]).x}
              y1={getCoordinatesForLine(lastMoveLine[0]).y}
              x2={getCoordinatesForLine(lastMoveLine[1]).x}
              y2={getCoordinatesForLine(lastMoveLine[1]).y}
              stroke={PALETTE.PATH_INDICATOR}
              strokeWidth="0.6"
              className="opacity-40"
              style={{ strokeDasharray: '0.8, 0.8' }}
            />
          </svg>
        )}
      </div>
    </div>
  );
};

export default ChessBoard;

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { GameState, GamePhase, Difficulty, Piece, PieceType } from './types';
import { getRandomSquare, getLegalMoves, canPieceReach } from './services/chessLogic';
import { PALETTE, PIECE_ICONS } from './constants';
import ChessBoard from './components/ChessBoard';

const OBSERVATION_TIME = 5;
const START_TIME = 180; 
const MAX_STRIKES = 5;

const App: React.FC = () => {
  const [state, setState] = useState<GameState>({
    phase: 'START',
    difficulty: Difficulty.EASY,
    pieces: [],
    targetSquare: null,
    score: 0,
    strikes: 0,
    timeLeft: START_TIME,
    lastMoveLine: null,
    correctMoves: 0,
    currentStreak: 0,
    bestStreak: 0,
  });

  const timerRef = useRef<any>(null);
  const [disabledOptions, setDisabledOptions] = useState<PieceType[]>([]);
  const [pulsingPiece, setPulsingPiece] = useState<PieceType | null>(null);

  const generateNewTarget = useCallback((currentPieces: Piece[]) => {
    const randomPiece = currentPieces[Math.floor(Math.random() * currentPieces.length)];
    const legalMoves = getLegalMoves(randomPiece.square, randomPiece.type);
    const availableTargets = legalMoves.filter(m => !currentPieces.some(p => p.square === m));

    if (availableTargets.length === 0) {
      return legalMoves[Math.floor(Math.random() * legalMoves.length)];
    }

    return availableTargets[Math.floor(Math.random() * availableTargets.length)];
  }, []);

  const startGame = (diff: Difficulty) => {
    let pieceCount = 2;
    if (diff === Difficulty.INTERMEDIATE) pieceCount = 3;
    if (diff === Difficulty.HARD) pieceCount = 4;

    const pieceTypes: PieceType[] = ['QUEEN', 'ROOK', 'BISHOP', 'KNIGHT'];
    const selectedPieces: Piece[] = [];
    const usedSquares: number[] = [];

    for (let i = 0; i < pieceCount; i++) {
      let type;
      if (diff === Difficulty.EASY && i === 1) {
        const firstType = selectedPieces[0].type;
        const available = pieceTypes.filter(t => t !== firstType);
        type = available[Math.floor(Math.random() * available.length)];
      } else {
        type = pieceTypes[Math.floor(Math.random() * pieceTypes.length)];
      }

      const square = getRandomSquare(usedSquares);
      usedSquares.push(square);
      selectedPieces.push({
        id: `p-${i}`,
        type,
        square,
        isVisible: true
      });
    }

    setState({
      phase: 'OBSERVING',
      difficulty: diff,
      pieces: selectedPieces,
      targetSquare: null,
      score: 0,
      strikes: 0,
      timeLeft: START_TIME,
      lastMoveLine: null,
      correctMoves: 0,
      currentStreak: 0,
      bestStreak: 0,
    });

    setTimeout(() => {
      setState(prev => {
        const nextTarget = generateNewTarget(prev.pieces);
        return {
          ...prev,
          phase: 'PLAYING',
          pieces: prev.pieces.map(p => ({ ...p, isVisible: false })),
          targetSquare: nextTarget,
        };
      });
    }, OBSERVATION_TIME * 1000);
  };

  useEffect(() => {
    if (state.phase === 'PLAYING') {
      timerRef.current = setInterval(() => {
        setState(prev => {
          if (prev.timeLeft <= 1) {
            clearInterval(timerRef.current!);
            return { ...prev, timeLeft: 0, phase: 'GAMEOVER' };
          }
          return { ...prev, timeLeft: prev.timeLeft - 1 };
        });
      }, 1000);
    }
    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, [state.phase]);

  const handlePieceSelect = (type: PieceType) => {
    if (state.phase !== 'PLAYING' || state.targetSquare === null) return;

    const validPiece = state.pieces.find(p => p.type === type && canPieceReach(p.square, state.targetSquare!, p.type));

    if (validPiece) {
      const oldSquare = validPiece.square;
      const newSquare = state.targetSquare!;

      const updatedPieces = state.pieces.map(p => 
        p.id === validPiece.id ? { ...p, square: newSquare } : p
      );

      setDisabledOptions([]);
      const nextTarget = generateNewTarget(updatedPieces);

      setState(prev => {
        const newStreak = prev.currentStreak + 1;
        return {
          ...prev,
          score: prev.score + 10,
          pieces: updatedPieces,
          lastMoveLine: [oldSquare, newSquare],
          targetSquare: nextTarget,
          correctMoves: prev.correctMoves + 1,
          currentStreak: newStreak,
          bestStreak: Math.max(prev.bestStreak, newStreak),
        };
      });
    } else {
      setPulsingPiece(type);
      setTimeout(() => setPulsingPiece(null), 400);

      setDisabledOptions(prev => [...prev, type]);
      setState(prev => {
        const newStrikes = prev.strikes + 1;
        if (newStrikes >= MAX_STRIKES) {
          clearInterval(timerRef.current!);
          return { ...prev, strikes: newStrikes, phase: 'GAMEOVER', currentStreak: 0 };
        }
        return { ...prev, strikes: newStrikes, currentStreak: 0 };
      });
    }
  };

  const renderStartScreen = () => (
    <div className="flex flex-col items-center justify-center h-full space-y-12 animate-in fade-in duration-1000">
      <div className="text-center">
        <h1 
          className="text-5xl font-extralight tracking-[0.3em] mb-4 uppercase"
          style={{ color: PALETTE.PRIMARY_TEXT }}
        >Academy Drill</h1>
        <p 
          className="font-bold tracking-[0.5em] text-[10px] uppercase"
          style={{ color: PALETTE.HIGHLIGHT_OUTLINE }}
        >Venture Chess Visualization Trainer</p>
      </div>

      <div className="grid grid-cols-1 gap-4 w-72">
        {[
          { id: Difficulty.EASY, label: 'Level I: Two Pieces' },
          { id: Difficulty.INTERMEDIATE, label: 'Level II: Three Pieces' },
          { id: Difficulty.HARD, label: 'Level III: Four Pieces' }
        ].map(diff => (
          <button 
            key={diff.id}
            onClick={() => startGame(diff.id)}
            className="border py-4 px-6 transition-all uppercase tracking-[0.2em] text-[10px] font-bold shadow-sm"
            style={{ 
              backgroundColor: PALETTE.SECONDARY_BG,
              borderColor: PALETTE.MUTED_ELEMENTS,
              color: PALETTE.MUTED_ELEMENTS
            }}
            onMouseOver={(e) => {
              e.currentTarget.style.backgroundColor = PALETTE.PRIMARY_TEXT;
              e.currentTarget.style.color = '#FFFFFF';
            }}
            onMouseOut={(e) => {
              e.currentTarget.style.backgroundColor = PALETTE.SECONDARY_BG;
              e.currentTarget.style.color = PALETTE.MUTED_ELEMENTS;
            }}
          >
            {diff.label}
          </button>
        ))}
      </div>
    </div>
  );

  const renderGameScreen = () => (
    <div className="flex flex-col items-center w-full max-w-6xl px-4 animate-in fade-in duration-500">
      <div 
        className="flex justify-between items-center w-full max-w-[560px] mb-8 font-mono text-xs tracking-widest border-b pb-4"
        style={{ borderColor: `${PALETTE.MUTED_ELEMENTS}40` }}
      >
        <div className="flex space-x-12">
          <div className="flex flex-col">
            <span className="text-[8px] mb-1 font-bold" style={{ color: PALETTE.MUTED_ELEMENTS }}>SCORE</span>
            <span className="text-lg font-bold" style={{ color: PALETTE.PRIMARY_TEXT }}>{state.score.toString().padStart(4, '0')}</span>
          </div>
          <div className="flex flex-col">
            <span className="text-[8px] mb-1 font-bold" style={{ color: PALETTE.MUTED_ELEMENTS }}>TIME</span>
            <span className="text-lg font-bold" style={{ color: state.timeLeft < 15 ? '#EF4444' : PALETTE.PRIMARY_TEXT }}>
              {Math.floor(state.timeLeft / 60)}:{(state.timeLeft % 60).toString().padStart(2, '0')}
            </span>
          </div>
        </div>

        <div className="flex flex-col items-end">
          <span className="text-[8px] mb-2 font-bold" style={{ color: PALETTE.MUTED_ELEMENTS }}>STRIKES</span>
          <div className="flex space-x-1.5">
            {Array.from({ length: MAX_STRIKES }).map((_, i) => (
              <div 
                key={i} 
                className="w-4 h-1 transition-colors duration-300"
                style={{ backgroundColor: i < state.strikes ? '#EF4444' : `${PALETTE.MUTED_ELEMENTS}40` }} 
              />
            ))}
          </div>
        </div>
      </div>

      <ChessBoard 
        pieces={state.pieces} 
        targetSquare={state.targetSquare} 
        lastMoveLine={state.lastMoveLine} 
      />

      <div className="mt-12 flex flex-col items-center w-full max-w-[500px]">
        <div 
          className="flex justify-center space-x-6 p-6 border rounded shadow-sm"
          style={{ 
            borderColor: `${PALETTE.MUTED_ELEMENTS}20`,
            backgroundColor: PALETTE.SECONDARY_BG,
            opacity: state.phase !== 'PLAYING' ? 0.2 : 1 
          }}
        >
          {(['QUEEN', 'ROOK', 'BISHOP', 'KNIGHT'] as PieceType[]).map((type) => {
            const isUsedInSession = state.pieces.some(p => p.type === type);
            const isDisabled = disabledOptions.includes(type);
            const isPulsing = pulsingPiece === type;

            return (
              <button
                key={type}
                onClick={() => handlePieceSelect(type)}
                disabled={isDisabled || !isUsedInSession}
                className={`w-20 h-24 p-2 border transition-all active:scale-95 flex flex-col items-center justify-between rounded ${isPulsing ? 'animate-subtle-pulse' : ''}`}
                style={{ 
                  display: isUsedInSession ? 'flex' : 'none',
                  backgroundColor: PALETTE.SECONDARY_BG,
                  borderColor: isPulsing ? '#EF4444' : `${PALETTE.MUTED_ELEMENTS}30`,
                  opacity: isDisabled && !isPulsing ? 0.3 : 1,
                  boxShadow: '0 1px 3px 0 rgb(0 0 0 / 0.1)'
                }}
              >
                <div className="w-full h-14 flex items-center justify-center">
                  {PIECE_ICONS[type]}
                </div>
                <span className="text-[9px] font-bold uppercase tracking-widest pb-1" style={{ color: PALETTE.MUTED_ELEMENTS }}>{type}</span>
              </button>
            );
          })}
        </div>

        <div 
          className="mt-10 text-[10px] font-bold uppercase tracking-[0.4em] text-center"
          style={{ color: state.phase === 'OBSERVING' ? PALETTE.HIGHLIGHT_OUTLINE : PALETTE.MUTED_ELEMENTS }}
        >
          {state.phase === 'OBSERVING' ? 'Memorize piece locations' : 'Select the piece that can reach the square'}
        </div>
      </div>
    </div>
  );

  const renderGameOver = () => (
    <div className="flex flex-col items-center justify-center h-full space-y-12 animate-in fade-in zoom-in duration-1000">
      <div className="text-center">
        <h2 className="text-5xl font-extralight tracking-[0.3em] mb-4 uppercase" style={{ color: PALETTE.PRIMARY_TEXT }}>Session Over</h2>
        <p className="uppercase tracking-[0.4em] text-[10px] font-bold" style={{ color: PALETTE.MUTED_ELEMENTS }}>Analysis Terminated</p>
      </div>

      <div className="flex flex-col items-center space-y-2">
        <div className="uppercase tracking-[0.5em] text-[8px] font-bold" style={{ color: PALETTE.MUTED_ELEMENTS }}>Performance Rating</div>
        <div className="text-8xl font-black tracking-tighter" style={{ color: PALETTE.HIGHLIGHT_OUTLINE }}>{state.score}</div>
      </div>

      <div className="flex flex-col items-center space-y-4 w-full max-w-sm">
