                className={`w-28 h-32 p-3 border transition-all active:scale-95 flex flex-col items-center justify-between rounded-sm ${isPulsing ? 'animate-subtle-pulse' : ''}`}
                style={{ 
                  backgroundColor: PALETTE.SECONDARY_BG,
