type GamePhase = 'LOBBY' | 'OBSERVE' | 'CHALLENGE' | 'FEEDBACK' | 'GAMEOVER';

const App: React.FC = () => {
  const [phase, setPhase] = useState<GamePhase>('LOBBY');
  const [difficulty, setDifficulty] = useState(2);
  const [fen, setFen] = useState('rnbqkbnr/pppppppp/8/8/8/8/PPPPPPPP/RNBQKBNR w KQkq - 0 1');
  const [targetSquare, setTargetSquare] = useState<string | null>(null);
  const [score, setScore] = useState(0);
  const [bestScore, setBestScore] = useState(0);
  const [strikes, setStrikes] = useState(0);
  const [timeLeft, setTimeLeft] = useState(180);
  const [moveHistory, setMoveHistory] = useState<string[]>([]);
  const [feedback, setFeedback] = useState<{ type: 'success' | 'error', piece: string } | null>(null);

  const timerRef = useRef<number | null>(null);

  const startNewDrill = useCallback(() => {
    const newFen = generateRandomPosition(difficulty);
    setFen(newFen);
    setPhase('OBSERVE');
    setTargetSquare(null);
    setFeedback(null);

    // After 5 seconds, hide pieces and show target
    setTimeout(() => {
      const chess = new Chess(newFen);
      const board = chess.board();
      const occupiedSquares: string[] = [];
      board.forEach((row, r) => {
        row.forEach((piece, c) => {
          if (piece && piece.type !== 'k') {
            occupiedSquares.push(`${String.fromCharCode(97 + c)}${8 - r}`);
          }
        });
      });

      const randomStartSquare = occupiedSquares[Math.floor(Math.random() * occupiedSquares.length)];
      const moves = chess.moves({ square: randomStartSquare as Square, verbose: true });

      if (moves.length > 0) {
        setTargetSquare(moves[Math.floor(Math.random() * moves.length)].to);
      } else {
        setTargetSquare('e4');
      }

      setPhase('CHALLENGE');
    }, 5000);
  }, [difficulty]);

  const handleStart = () => {
    setScore(0);
    setStrikes(0);
    setTimeLeft(180);
    setMoveHistory([]);
    startNewDrill();
  };

  const handlePieceGuess = (pieceType: string) => {
    if (phase !== 'CHALLENGE') return;

    const isCorrect = isValidVisualizationMove(fen, pieceType, targetSquare!);

    if (isCorrect) {
      setScore(s => s + 10);
      setFeedback({ type: 'success', piece: pieceType });
      setMoveHistory(prev => [...prev, `${pieceType} → ${targetSquare}`]);
    } else {
      setStrikes(s => s + 1);
      setFeedback({ type: 'error', piece: pieceType });
    }

    setPhase('FEEDBACK');

    // Clear the visual cue after 1 second explicitly
    setTimeout(() => {
      setFeedback(null);
      if (strikes >= 4 && !isCorrect) {
        setPhase('GAMEOVER');
        if (score > bestScore) setBestScore(score);
      } else {
        startNewDrill();
      }
    }, 1000);
  };

  useEffect(() => {
    if (phase === 'CHALLENGE' || phase === 'OBSERVE') {
      timerRef.current = window.setInterval(() => {
        setTimeLeft(t => {
          if (t <= 1) {
            setPhase('GAMEOVER');
            return 0;
          }
          return t - 1;
        });
      }, 1000);
    } else {
      if (timerRef.current) clearInterval(timerRef.current);
    }
    return () => { if (timerRef.current) clearInterval(timerRef.current); };
  }, [phase]);

  return (
    <div className="flex flex-col h-screen max-h-screen">
      <header className="flex items-center justify-between px-6 py-2 bg-[#262421] border-b border-[#3d3a37] z-30">
        <div className="flex items-center space-x-6">
          <div className="flex items-center space-x-2 cursor-pointer group">
            <Brain className="w-8 h-8 text-[#bababa] group-hover:text-white transition-colors" />
            <h1 className="text-xl font-bold tracking-tight text-[#bababa] group-hover:text-white transition-colors uppercase">
              Venture <span className="text-[#629924]">Academy</span>
            </h1>
          </div>
        </div>
        <div className="flex items-center space-x-4">
          <div className="flex items-center space-x-2 bg-[#161512] px-3 py-1 rounded-sm border border-[#3d3a37]">
            <Trophy className="w-4 h-4 text-yellow-500" />
            <span className="text-xs font-bold text-white">{bestScore}</span>
          </div>
          <div className="w-8 h-8 bg-[#629924] rounded-sm flex items-center justify-center text-xs font-bold text-white">
            GM
