                        >
                          {l}
                        </button>
                      ))}
                    </div>
                  </div>
                  <button 
                    onClick={handleStart}
                    className="w-full py-4 bg-[#629924] hover:bg-[#72b02a] text-white font-bold uppercase tracking-[0.2em] rounded-sm flex items-center justify-center space-x-2 transition-all shadow-lg active:scale-95"
                  >
                    <Play className="w-4 h-4 fill-current" />
                    <span>Initiate Scan</span>
                  </button>
                </div>
              </div>
            )}

            {phase === 'GAMEOVER' && (
              <div className="absolute inset-0 z-20 flex flex-col items-center justify-center bg-black/80 backdrop-blur-md rounded-sm">
                <h2 className="text-4xl font-black text-white mb-2 uppercase tracking-tighter">Drill Concluded</h2>
                <p className="text-[#bababa] uppercase tracking-[0.4em] text-[10px] mb-8">Performance Summary Generated</p>
                <div className="grid grid-cols-2 gap-4 w-80 mb-8">
                  <div className="bg-[#262421] p-4 border border-[#3d3a37] text-center">
                    <div className="text-[8px] font-bold text-[#bababa] uppercase tracking-widest mb-1">Score</div>
                    <div className="text-3xl font-black text-white">{score}</div>
                  </div>
                  <div className="bg-[#262421] p-4 border border-[#3d3a37] text-center">
                    <div className="text-[8px] font-bold text-[#bababa] uppercase tracking-widest mb-1">Streak</div>
                    <div className="text-3xl font-black text-[#629924]">{moveHistory.length}</div>
                  </div>
                </div>
                <button 
                  onClick={handleStart}
                  className="px-12 py-4 bg-white text-black font-bold uppercase tracking-[0.2em] rounded-sm hover:bg-[#bababa] transition-all flex items-center space-x-2"
                >
                  <RefreshCw className="w-4 h-4" />
                  <span>Restart Drill</span>
                </button>
              </div>
            )}

            <ChessBoard 
              fen={fen} 
              isVisible={phase === 'OBSERVE' || phase === 'FEEDBACK'} 
              targetSquare={targetSquare}
