      const randomStartSquare = occupiedSquares[Math.floor(Math.random() * occupiedSquares.length)];
      const moves = chess.moves({ square: randomStartSquare as Square, verbose: true });

      if (moves.length > 0) {
        setTargetSquare(moves[Math.floor(Math.random() * moves.length)].to);
      } else {
        // Fallback to any legal move in the position if the selected piece has none
        const allMoves = chess.moves({ verbose: true });
        if (allMoves.length > 0) {
          setTargetSquare(allMoves[Math.floor(Math.random() * allMoves.length)].to);
        } else {
          setTargetSquare('e4');
        }
      }

      setPhase('CHALLENGE');
    }, 4000);
