import { Chess, Square } from 'chess.js';

/**
 * Generates a random legal chess position with a specific piece count.
 * Includes both kings to ensure FEN validity for chess.js.
 */
export function generateRandomPosition(pieceCount: number): string {
  const chess = new Chess();
  chess.clear();

  // Always include kings for validity. Lichess-style validation requires both.
  chess.put({ type: 'k', color: 'w' }, 'e1');
  chess.put({ type: 'k', color: 'b' }, 'e8');

  const pieces: ('q' | 'r' | 'b' | 'n')[] = ['q', 'r', 'b', 'n'];
  const squares = Array.from({ length: 64 }, (_, i) => {
    const f = String.fromCharCode(97 + (i % 8));
    const r = Math.floor(i / 8) + 1;
    return `${f}${r}` as Square;
  }).filter(s => s !== 'e1' && s !== 'e8');

  for (let i = 0; i < pieceCount; i++) {
    const p = pieces[Math.floor(Math.random() * pieces.length)];
    const s = squares.splice(Math.floor(Math.random() * squares.length), 1)[0];
    chess.put({ type: p, color: 'w' }, s);
  }

  return chess.fen();
}

/**
 * Checks if a move is valid for the target piece type in the given position.
 */
export function isValidVisualizationMove(fen: string, pieceType: string, targetSquare: string): boolean {
  try {
    const chess = new Chess(fen);
    const board = chess.board();

    for (let r = 0; r < 8; r++) {
      for (let c = 0; c < 8; c++) {
        const piece = board[r][c];
        // We look for any white piece of the requested type
        if (piece && piece.color === 'w' && piece.type === pieceType.toLowerCase()) {
          const from = `${String.fromCharCode(97 + c)}${8 - r}` as Square;
          const moves = chess.moves({ square: from, verbose: true });
          if (moves.some(m => m.to === targetSquare)) return true;
        }
      }
    }
  } catch (e) {
    console.error("Invalid FEN processed in move validation", fen, e);
  }
  return false;
}

export function getRandomSquare(exclude: number[] = []): number {
  let sq;
  do {
    sq = Math.floor(Math.random() * 64);
  } while (exclude.includes(sq));
  return sq;
}

