            style={{ 
              backgroundColor: PALETTE.SECONDARY_BG,
              borderColor: `${PALETTE.PRIMARY_TEXT}25`,
              color: PALETTE.PRIMARY_TEXT
            }}
          >
            {diff.label}
          </button>
        ))}
      </div>

      <div className="pt-12 opacity-80 italic text-[14px] serif" style={{ color: PALETTE.PRIMARY_TEXT }}>
        "Vision is the art of seeing what is invisible to others."
      </div>
    </div>
  );

  const renderGameScreen = () => (
    <div className="flex flex-col items-center w-full max-w-6xl px-4 animate-in fade-in duration-700 pb-20 pt-10">
      {/* Redesigned HUD Dashboard */}
      <div className="w-full max-w-[660px] mb-10 select-none">
        <div className="glass-panel p-6 rounded-2xl shadow-xl flex items-center justify-between border-white/50">
          {/* Left Side: Stats */}
          <div className="flex items-center space-x-10">
            <div className="flex flex-col">
