                {Math.floor(state.timeLeft / 60)}:{(state.timeLeft % 60).toString().padStart(2, '0')}
              </span>
            </div>
          </div>

          {/* Right Side: Strikes & Controls */}
          <div className="flex items-center space-x-6">
