                {/* Highlighted Target Square */}
                {targetSquare === i && (
                  <div 
                    className="absolute inset-0 bg-white/10 border-[4px] pointer-events-none z-10 animate-pulse-slow" 
                    style={{ borderColor: 'rgba(255, 255, 255, 0.6)' }}
