          )}
        </div>

        {/* Right Ranks Gutter */}
        <div className="flex flex-col w-5 sm:w-7 h-[320px] sm:h-[400px] md:h-[500px] lg:h-[540px]" style={{ backgroundColor: PALETTE.BOARD_DARK }}>
